describe('Running Settings — HR Zones Section', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubProfileLoaded()
    stubStravaConnected()
    cy.viewport(1280, 720)
  })

  it('threshold input is hidden when method is max_hr', () => {
    stubSettingsLoaded({ hr_zones_method: 'max_hr', threshold_hr: null })
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.hr_zones_loading}`).should('not.exist')
    cy.get(`#${IDS.threshold_hr_input}`).should('not.exist')
  })

  it('selecting Lactate Threshold reveals threshold HR input', () => {
    stubSettingsLoaded({ hr_zones_method: 'max_hr', threshold_hr: null })
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.hr_zones_loading}`).should('not.exist')

    // Open the Select dropdown and pick threshold option
    cy.get(`#${IDS.hr_zones_method_select}`).click()
    cy.contains('[role="option"]', 'Lactate Threshold').click()

    cy.get(`#${IDS.threshold_hr_input}`).should('be.visible')
  })

  it('threshold client-side validation — leaving threshold empty shows error without firing API', () => {
    stubSettingsLoaded({ hr_zones_method: 'max_hr', threshold_hr: null })
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.hr_zones_loading}`).should('not.exist')

    // Switch to threshold method
    cy.get(`#${IDS.hr_zones_method_select}`).click()
    cy.contains('[role="option"]', 'Lactate Threshold').click()

    // Leave threshold input empty and click Save
    cy.intercept('PATCH', SETTINGS_API).as('patchSettings')
    cy.get(`#${IDS.hr_zones_save_btn}`).click()

    cy.get(`#${IDS.hr_zones_save_error}`).should('be.visible')
    // API should NOT have been called
    cy.get('@patchSettings.all').should('have.length', 0)
  })

  it('save HR zones → shows success on 200', () => {
    stubSettingsLoaded({ hr_zones_method: 'max_hr', threshold_hr: null })
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.hr_zones_loading}`).should('not.exist')

    // Switch to Karvonen method
    cy.get(`#${IDS.hr_zones_method_select}`).click()
    cy.contains('[role="option"]', 'Karvonen').click()

    cy.intercept('PATCH', SETTINGS_API, {
      statusCode: 200,
      body: { data: { hr_zones_method: 'karvonen' }, message: 'Settings updated' },
    }).as('patchSettingsKarvonen')

    cy.get(`#${IDS.hr_zones_save_btn}`).click()
    cy.wait('@patchSettingsKarvonen')
    cy.get(`#${IDS.hr_zones_save_success}`).should('be.visible')
  })
})

