describe('Running Settings — Strava Connection (connected state)', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubProfileLoaded()
    stubSettingsLoaded()
    cy.viewport(1280, 720)
  })

  it('connected state shows the connected card and Disconnect button', () => {
    stubStravaConnected()
    cy.visit(SETTINGS_URL)
    // scrollIntoView is needed because the card parent has overflow:hidden which clips visibility
    cy.get(`#${STRAVA_IDS.settings_connected_state}`).scrollIntoView().should('be.visible')
    cy.get(`#${IDS.strava_disconnect_btn}`)
      .scrollIntoView()
      .should('be.visible')
      .and('contain.text', 'Disconnect')
  })

  it('Disconnect button → POST disconnect, then shows disconnected state', () => {
    stubStravaConnected()
    cy.visit(SETTINGS_URL)
    cy.get(`#${STRAVA_IDS.settings_connected_state}`).scrollIntoView().should('be.visible')

    cy.intercept('POST', STRAVA_DISCONNECT_API, {
      statusCode: 200,
      body: { data: null, message: 'Disconnected' },
    }).as('postDisconnect')

    // After disconnect, the page re-fetches strava status
    cy.intercept('GET', `**${STRAVA_STATUS_API}*`, {
      statusCode: 200,
      body: { data: { connected: false }, message: 'OK' },
    }).as('getStravaStatusAfterDisconnect')

    cy.get(`#${IDS.strava_disconnect_btn}`).click()
    cy.wait('@postDisconnect')
    cy.wait('@getStravaStatusAfterDisconnect')
    cy.get(`#${STRAVA_IDS.settings_disconnected_state}`).should('be.visible')
  })
})

