describe('Running Settings — Danger Zone', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.loginWithBypass()
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubProfileLoaded()
    stubSettingsLoaded()
    stubStravaConnected()
    cy.viewport(1280, 720)
    cy.visit(SETTINGS_URL)
    cy.get(`#${IDS.page}`).should('be.visible')
  })

  it('clicking Delete All opens the confirmation dialog', () => {
    cy.get(`#${IDS.danger_zone_delete_btn}`).click()
    cy.get(`#${IDS.danger_zone_dialog}`).should('be.visible')
  })

  it('confirm button is disabled when dialog first opens', () => {
    cy.get(`#${IDS.danger_zone_delete_btn}`).click()
    cy.get(`#${IDS.danger_zone_confirm_btn}`).should('be.disabled')
  })

  it('typing wrong text keeps confirm button disabled', () => {
    cy.get(`#${IDS.danger_zone_delete_btn}`).click()
    cy.get(`#${IDS.danger_zone_confirm_input}`).type('WRONG')
    cy.get(`#${IDS.danger_zone_confirm_btn}`).should('be.disabled')
  })

  it('typing DELETE enables confirm button and completing delete closes dialog', () => {
    cy.get(`#${IDS.danger_zone_delete_btn}`).click()
    cy.get(`#${IDS.danger_zone_confirm_input}`).clear().type('DELETE')
    cy.get(`#${IDS.danger_zone_confirm_btn}`).should('not.be.disabled')

    cy.intercept('DELETE', ACTIVITIES_API, {
      statusCode: 200,
      body: { data: { deleted: 5 }, message: 'All activity data deleted' },
    }).as('deleteActivities')

    cy.get(`#${IDS.danger_zone_confirm_btn}`).click()
    cy.wait('@deleteActivities')
    cy.get(`#${IDS.danger_zone_dialog}`).should('not.exist')
  })
})
